// paginationLabel renders the "Showing X–Y of N" line. When the current
// page has no rows but there are entries overall (e.g. user navigates
// past the last page via ?page=999) we render an explicit empty-page
// label instead of "Showing 0–0 of N" — the offset arithmetic isn't
// meaningful with zero rows, and the user needs a clear cue that the
// "← Newer" link is the way back.
func paginationLabel(page, pageSize, count int, total int64) string {
	if count == 0 {
		return fmt.Sprintf("Page %d is empty (%d entries total)", page, total)
	}
	start := (page-1)*pageSize + 1
	end := (page-1)*pageSize + count
	return fmt.Sprintf("Showing %d–%d of %d", start, end, total)
}

